        pub const name_field = struct {
            pub const number = 2;
            pub const name = "name";
            pub const json_name = "name";
            pub const cardinality = "optional";
            pub const kind = "string";
            pub const type_name = "string";
            pub const zig_type = "[]const u8";
            pub const has_type_ref = false;
