        pub fn cloneOwned(self: @This(), allocator: std.mem.Allocator) !@This() {
            var out = @This().init();
            errdefer out.deinit(allocator);
            out.active = self.active;
            out.count = self.count;
            out.total = self.total;
            out.delta = self.delta;
            out.big_delta = self.big_delta;
            out.checksum = self.checksum;
            out.token = self.token;
            out.signed_fixed = self.signed_fixed;
            out.signed_big_fixed = self.signed_big_fixed;
            out.ratio = self.ratio;
            out.score = self.score;
            out.kind = self.kind;
            if (self.flags.len != 0) {
                const cloned = try allocator.alloc(bool, self.flags.len);
                for (self.flags, 0..) |item, i| cloned[i] = item;
                out.flags = cloned;
