        pub fn mergeFrom(self: *@This(), allocator: std.mem.Allocator, other: @This()) !void {
            if (other.active) self.active = other.active;
            if (other.count != 0) self.count = other.count;
            if (other.total != 0) self.total = other.total;
            if (other.delta != 0) self.delta = other.delta;
            if (other.big_delta != 0) self.big_delta = other.big_delta;
            if (other.checksum != 0) self.checksum = other.checksum;
            if (other.token != 0) self.token = other.token;
            if (other.signed_fixed != 0) self.signed_fixed = other.signed_fixed;
            if (other.signed_big_fixed != 0) self.signed_big_fixed = other.signed_big_fixed;
            if (other.ratio != 0) self.ratio = other.ratio;
            if (other.score != 0) self.score = other.score;
            if (other.kind != 0) self.kind = other.kind;
            if (other.flags.len != 0) {
                const old = self.flags;
                const merged = try allocator.alloc(bool, old.len + other.flags.len);
                @memcpy(merged[0..old.len], old);
                @memcpy(merged[old.len..], other.flags);
                self.flags = merged;
                if (old.len != 0) allocator.free(old);
            }
            if (other.ids.len != 0) {
                const old = self.ids;
                const merged = try allocator.alloc(u64, old.len + other.ids.len);
                @memcpy(merged[0..old.len], old);
                @memcpy(merged[old.len..], other.ids);
                self.ids = merged;
                if (old.len != 0) allocator.free(old);
            }
            try pbz.wire.appendRawFieldsClone(allocator, &self._unknown_fields, other._unknown_fields);
        }

        pub fn encodedSize(self: @This()) usize {
            var size: usize = 0;
            if (self.active) size += 1 + 1;
            if (self.count != 0) size += 1 + pbz.wire.encodedVarintSize(self.count);
            if (self.total != 0) size += 1 + pbz.wire.encodedVarintSize(self.total);
            if (self.delta != 0) size += 1 + pbz.wire.encodedVarintSize(pbz.wire.zigZagEncode32(self.delta));
            if (self.big_delta != 0) size += 1 + pbz.wire.encodedVarintSize(pbz.wire.zigZagEncode64(self.big_delta));
            if (self.checksum != 0) size += 1 + 4;
            if (self.token != 0) size += 1 + 8;
            if (self.signed_fixed != 0) size += 1 + 4;
            if (self.signed_big_fixed != 0) size += 1 + 8;
            if (self.ratio != 0) size += 1 + 4;
            if (self.score != 0) size += 1 + 8;
            if (self.kind != 0) size += 1 + pbz.wire.encodedVarintSize(@as(u64, @bitCast(@as(i64, self.kind))));
            if (self.flags.len != 0) {
                const packed_len = self.flags.len * 1;
                size += 1 + pbz.wire.encodedVarintSize(packed_len) + packed_len;
            }
            if (self.ids.len != 0) {
                var packed_len: usize = 0;
                for (self.ids) |item| packed_len += pbz.wire.encodedVarintSize(item);
                size += 1 + pbz.wire.encodedVarintSize(packed_len) + packed_len;
            }
            for (self._unknown_fields) |raw| size += raw.len;
            return size;
        }

        pub fn writeTo(self: @This(), w: *pbz.Writer) !void {
            if (self.active) try w.writeBool(1, self.active);
            if (self.count != 0) try w.writeUInt32(2, self.count);
            if (self.total != 0) try w.writeUInt64(3, self.total);
            if (self.delta != 0) try w.writeSInt32(4, self.delta);
            if (self.big_delta != 0) try w.writeSInt64(5, self.big_delta);
            if (self.checksum != 0) try w.writeFixed32(6, self.checksum);
            if (self.token != 0) try w.writeFixed64(7, self.token);
            if (self.signed_fixed != 0) try w.writeSFixed32(8, self.signed_fixed);
            if (self.signed_big_fixed != 0) try w.writeSFixed64(9, self.signed_big_fixed);
            if (self.ratio != 0) try w.writeFloat(10, self.ratio);
            if (self.score != 0) try w.writeDouble(11, self.score);
            if (self.kind != 0) try w.writeInt32(12, self.kind);
            if (self.flags.len != 0) {
                const packed_len = self.flags.len * 1;
                try w.writeTag(13, .length_delimited);
                try w.writeVarint(packed_len);
                try w.appendSlice(std.mem.sliceAsBytes(self.flags));
            }
            if (self.ids.len != 0) {
                var packed_len: usize = 0;
                for (self.ids) |item| packed_len += pbz.wire.encodedVarintSize(item);
                try w.writeTag(14, .length_delimited);
                try w.writeVarint(packed_len);
                for (self.ids) |item| try w.writeVarint(item);
            }
            for (self._unknown_fields) |raw| try w.appendSlice(raw);
        }

        pub fn writeToAssumeCapacity(self: @This(), w: *pbz.Writer) !void {
