                        var sort_j = sort_i;
                        while (sort_j > 0 and pbz.wire.bytesLessThan(item.key, entries[sort_j - 1].key)) : (sort_j -= 1) entries[sort_j] = entries[sort_j - 1];
                        entries[sort_j] = item;
                    }
                } else {
                    const entries_already_sorted = sorted: {
                        var check_i: usize = 1;
                        while (check_i < entries.len) : (check_i += 1) {
