                        }
                        break :sorted true;
                    };
                    if (!entries_already_sorted) {
                        std.mem.sort(auditsEntry, entries, {}, struct { fn lessThan(_: void, a: auditsEntry, b: auditsEntry) bool { return pbz.wire.bytesLessThan(a.key, b.key); } }.lessThan);
                    }
